// A small string-emitting C# writer (no .NET toolchain). Assembles files with
// the machine-ownership header, `using` directives and a file-scoped namespace
// (C# 10+), plus XML `///` doc comments. `.cs`/`.csproj` are not extensions the
// framework orchestrator knows a comment syntax for, so — unlike the Go/Python
// emitters, which lean on `fileHeader` — this emitter bakes the ownership marker
// directly into every file here.

/** The `// <auto-generated/>` ownership block prepended to every .cs file. */
export const CS_HEADER = ['// <auto-generated>', '//     Code generated by opensdk. DO NOT EDIT.', '// </auto-generated>'].join('\n');

/** The XML-comment ownership marker prepended to the .csproj. */
export const CSPROJ_HEADER = '<!-- Code generated by opensdk. DO NOT EDIT. -->';

/**
 * Assemble a complete C# file: ownership header, sorted `using` directives, the
 * file-scoped namespace declaration, and the type declarations (blank-line
 * separated). Empty declarations are dropped.
 */
export function csFile(usings: string[], namespaceName: string, decls: string[]): string {
  const parts: string[] = [CS_HEADER, ''];
  if (usings.length > 0) {
    parts.push([...usings].sort().map((u) => `using ${u};`).join('\n'), '');
  }
  parts.push(`namespace ${namespaceName};`, '');
  parts.push(decls.filter(Boolean).join('\n\n'));
  return `${parts.join('\n')}\n`;
}

/** Escape text for an XML doc comment. */
function escapeXml(text: string): string {
  return text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

/** A C# `/// <summary>...</summary>` doc comment from free text, or '' when empty. */
export function csDoc(text: string | undefined): string {
  const raw = (text || '').trim();
  if (!raw) return '';
  const lines = raw.split('\n').map((l) => l.trim()).filter(Boolean);
  if (lines.length === 1) return `/// <summary>${escapeXml(lines[0])}</summary>`;
  return ['/// <summary>', ...lines.map((l) => `/// ${escapeXml(l)}`), '/// </summary>'].join('\n');
}

/** Indent every non-empty line of a block by `depth` 4-space levels. */
export function indent(block: string, depth = 1): string {
  const pad = '    '.repeat(depth);
  return block
    .split('\n')
    .map((line) => (line ? `${pad}${line}` : line))
    .join('\n');
}
